from beeai.memory import MemoryBuffer
import re

def scan_memory_loops(memory_buffer: MemoryBuffer, max_distance: int = 5):
    tool_calls = []
    for entry in memory_buffer.entries:
        if 'tool_call' in entry.content:
            # Extract tool signature
            match = re.search(r'tool_name.*?([\w_]+).*?parameters\s*([\s\S]*?)}', entry.content)
            if match:
                tool_calls.append(f'{match.group(1)}:{hash(match.group(2))}')

    if len(tool_calls) < 10:
        return False

    # Check for repeating sequences
    for i in range(len(tool_calls) - 10):
        seq1 = tool_calls[i:i+5]
        seq2 = tool_calls[i+5:i+10]
        distance = sum(a != b for a, b in zip(seq1, seq2))
        if distance <= max_distance:
            print(f'🔄 Memory loop detected at index {i}: distance={distance}')
            return True
    return False

from beeai import BeeAgent
from collections import defaultdict

def detect_event_cycles(agent: BeeAgent):
    graph = defaultdict(list)
    event_chain = []

    for event in agent.trace_history:
        if event.type == 'TOOL_CALL':
            event_chain.append(event.tool_name)

    # Build tool dependency graph
    for i in range(len(event_chain) - 1):
        graph[event_chain[i]].append(event_chain[i+1])

    # Detect cycles (simple approach)
    visited = set()
    def has_cycle(node):
        if node in visited:
            return True
        visited.add(node)
        return any(has_cycle(neighbor) for neighbor in graph[node])

    for node in graph:
        visited.clear()
        if has_cycle(node):
            print(f'🔄 Cycle detected involving tool: {node}')
            return True
    return False

