from beeai import BeeAgent, Tool
from typing import Dict, Any

def create_loop_safe_agent():
    class LoopSafeAgent(BeeAgent):
        def __init__(self, *args, **kwargs):
            super().__init__(*args, **kwargs)
            self.tool_usage = defaultdict(int)
            self.tool_limits = {'calculator': 5, 'search': 8, 'default': 3}

        def should_call_tool(self, tool: Tool, params: Dict[str, Any]) -> bool:
            limit = self.tool_limits.get(tool.name, self.tool_limits['default'])
            if self.tool_usage[tool.name] >= limit:
                self.say(f'⏹️ Tool quota exceeded: {tool.name}. Switching strategy.')
                return False
            self.tool_usage[tool.name] += 1
            return True

    return LoopSafeAgent(
        model='granite-3.0',
        memory_size_limit='64k',
        max_tool_calls_per_turn=2
    )
